($$a9596cca-661e-42b1-9bd7-eb0eb871141d$$,$$U 1114$$,NULL,60.0177,17.41,$$[ketil lit ' kera bro eftʀ ' selfan sik ok fastr + iftʀ + i… …-aþi-… … runoʀ þisaʀ]$$,$$"Ketill lét gera brú eptir sjalfan sik ok "Fastr(?) eptir … … … rúnar þessar.$$,NULL,$$Ketill had the bridge made in memory of himself; and Fastr(?) in memory of … these runes.$$,NULL,NULL,$$Runsten$$,$$Sten$$,$$Uppland$$,$$Sweden$$),
